#include "mainwindow.h"
#include <QApplication>
MainWindow::MainWindow(QWidget*p):QMainWindow(p){setWindowTitle("Grand Azure — Hotel Management System");QScreen*sc=QApplication::primaryScreen();QRect sg=sc->availableGeometry();int w=qMin(sg.width()-40,1400);int h=qMin(sg.height()-60,860);resize(w,h);move((sg.width()-w)/2,(sg.height()-h)/2);setMinimumSize(1100,680);hotel.initDefaultRooms();hotel.initDatabase();buildUI();refreshDashboard();}
void MainWindow::buildUI(){auto*root=new QWidget(this);root->setStyleSheet("background:#F8F4EE;");setCentralWidget(root);auto*hlay=new QHBoxLayout(root);hlay->setContentsMargins(0,0,0,0);hlay->setSpacing(0);hlay->addWidget(buildSidebar());stack=new QStackedWidget(root);stack->addWidget(buildDashboard());stack->addWidget(buildRoomsPage());stack->addWidget(buildGuestsPage());stack->addWidget(buildBookingPage());stack->addWidget(buildBillingPage());stack->addWidget(buildRestaurantPage());stack->addWidget(buildLaundryPage());stack->addWidget(buildReportPage());hlay->addWidget(stack,1);switchPage(0);}
QWidget*MainWindow::buildSidebar(){auto*sb=new QWidget();sb->setFixedWidth(220);sb->setStyleSheet("background:#0F0F1A;");auto*vl=new QVBoxLayout(sb);vl->setContentsMargins(0,0,0,0);vl->setSpacing(0);auto*brand=new QWidget();brand->setStyleSheet("background:#0A0A14;border-bottom:1px solid rgba(212,175,55,0.15);");auto*bl=new QVBoxLayout(brand);bl->setContentsMargins(20,24,20,20);bl->setSpacing(4);auto*logo=new QLabel("✦ GRAND AZURE");logo->setStyleSheet("color:#D4AF37;font-size:15px;font-weight:800;letter-spacing:2px;");auto*sub=new QLabel("Hotel Management");sub->setStyleSheet("color:rgba(212,175,55,0.35);font-size:10px;letter-spacing:2px;");bl->addWidget(logo);bl->addWidget(sub);vl->addWidget(brand);auto mkSec=[](const QString&t)->QLabel*{auto*l=new QLabel(t);l->setStyleSheet("color:rgba(255,255,255,0.18);font-size:9px;letter-spacing:3px;font-weight:700;");l->setContentsMargins(24,18,0,4);return l;};btnDash=new SidebarButton("◈","Dashboard");btnRooms=new SidebarButton("⊞","Rooms");btnGuests=new SidebarButton("♟","Guests");btnBook=new SidebarButton("◉","Reservations");btnBill=new SidebarButton("◎","Billing");btnRestaurant=new SidebarButton("✦","Restaurant");btnLaundry=new SidebarButton("◆","Laundry");btnReport=new SidebarButton("≡","Reports");auto*grp=new QButtonGroup(this);for(auto*b:{btnDash,btnRooms,btnGuests,btnBook,btnBill,btnRestaurant,btnLaundry,btnReport})grp->addButton(b);vl->addWidget(mkSec("MAIN"));vl->addWidget(btnDash);vl->addWidget(btnRooms);vl->addWidget(mkSec("OPERATIONS"));vl->addWidget(btnGuests);vl->addWidget(btnBook);vl->addWidget(btnBill);vl->addWidget(mkSec("SERVICES"));vl->addWidget(btnRestaurant);vl->addWidget(btnLaundry);vl->addWidget(mkSec("ANALYTICS"));vl->addWidget(btnReport);vl->addStretch();auto*footer=new QWidget();footer->setStyleSheet("border-top:1px solid rgba(255,255,255,0.05);");auto*fl=new QHBoxLayout(footer);fl->setContentsMargins(20,16,20,16);fl->setSpacing(12);auto*av=new QLabel("A");av->setFixedSize(38,38);av->setAlignment(Qt::AlignCenter);av->setStyleSheet("background:#D4AF37;color:#0F0F1A;border-radius:19px;font-weight:800;font-size:14px;");auto*inf=new QWidget();auto*il=new QVBoxLayout(inf);il->setContentsMargins(0,0,0,0);il->setSpacing(2);auto*un=new QLabel("Admin");un->setStyleSheet("color:rgba(255,255,255,0.85);font-size:13px;font-weight:600;");auto*ur=new QLabel("Manager");ur->setStyleSheet("color:rgba(255,255,255,0.3);font-size:10px;");il->addWidget(un);il->addWidget(ur);fl->addWidget(av);fl->addWidget(inf);vl->addWidget(footer);connect(btnDash,&QPushButton::clicked,[this]{switchPage(0);refreshDashboard();});connect(btnRooms,&QPushButton::clicked,[this]{switchPage(1);refreshRoomTable();});connect(btnGuests,&QPushButton::clicked,[this]{switchPage(2);refreshGuestTable();});connect(btnBook,&QPushButton::clicked,[this]{switchPage(3);refreshBookingTable();});connect(btnBill,&QPushButton::clicked,[this]{switchPage(4);refreshBillingTable();});connect(btnRestaurant,&QPushButton::clicked,[this]{switchPage(5);refreshRestaurantTable();});connect(btnLaundry,&QPushButton::clicked,[this]{switchPage(6);refreshLaundryTable();});connect(btnReport,&QPushButton::clicked,[this]{switchPage(7);refreshDashboard();});return sb;}
QWidget*MainWindow::buildDashboard(){auto*lay=new QVBoxLayout();lay->setContentsMargins(32,28,32,28);lay->setSpacing(20);auto*hdr=new QWidget();auto*hl=new QHBoxLayout(hdr);hl->setContentsMargins(0,0,0,0);hl->addWidget(new SectionHeader("Dashboard","Welcome back, Admin — "+QDate::currentDate().toString("dddd, dd MMMM yyyy")));hl->addStretch();lay->addWidget(hdr);auto*cg=new QWidget();auto*cgl=new QHBoxLayout(cg);cgl->setContentsMargins(0,0,0,0);cgl->setSpacing(16);statAvail=new StatCard("Available Rooms","—","#38A169","🛏");statOccupied=new StatCard("Occupied Rooms","—","#D4AF37","🔑");statGuests=new StatCard("Total Guests","—","#3182CE","👤");statRevenue=new StatCard("Total Revenue","—","#805AD5","💰");cgl->addWidget(statAvail);cgl->addWidget(statOccupied);cgl->addWidget(statGuests);cgl->addWidget(statRevenue);lay->addWidget(cg);auto*ovBox=new QFrame();ovBox->setStyleSheet("QFrame{background:white;border-radius:16px;border:1px solid #F0EBE0;}");auto*ovl=new QVBoxLayout(ovBox);ovl->setContentsMargins(24,20,24,20);ovl->setSpacing(16);auto*ovHdr=new QWidget();auto*ovhl=new QHBoxLayout(ovHdr);ovhl->setContentsMargins(0,0,0,0);auto*ovt=new QLabel("Room Occupancy Overview");ovt->setStyleSheet("font-size:15px;font-weight:700;color:#1A1A2E;");ovhl->addWidget(ovt);ovhl->addStretch();auto*l1=new QLabel("● Available");l1->setStyleSheet("color:#38A169;font-size:12px;font-weight:600;");auto*l2=new QLabel("● Occupied");l2->setStyleSheet("color:#D4AF37;font-size:12px;font-weight:600;");ovhl->addWidget(l1);ovhl->addSpacing(16);ovhl->addWidget(l2);ovl->addWidget(ovHdr);auto*rg=new QWidget();auto*rgl=new QGridLayout(rg);rgl->setSpacing(8);int col=0,row=0;for(auto&r:hotel.rooms){auto*cell=new QPushButton(QString::number(r.number));cell->setFixedSize(56,40);cell->setCursor(Qt::PointingHandCursor);if(r.isAvailable)cell->setStyleSheet("QPushButton{background:#F0FFF4;color:#276749;border:1.5px solid #9AE6B4;border-radius:8px;font-size:12px;font-weight:700;}QPushButton:hover{background:#C6F6D5;border:1.5px solid #38A169;}");else cell->setStyleSheet("QPushButton{background:#FFFBEB;color:#92400E;border:1.5px solid #FCD34D;border-radius:8px;font-size:12px;font-weight:700;}QPushButton:hover{background:#FEF3C7;}");int rnum=r.number;connect(cell,&QPushButton::clicked,[this,rnum]{showRoomDetailDialog(rnum);});rgl->addWidget(cell,row,col);if(++col>=13){col=0;row++;}}ovl->addWidget(rg);lay->addWidget(ovBox);auto*rbBox=new QFrame();rbBox->setStyleSheet("QFrame{background:white;border-radius:16px;border:1px solid #F0EBE0;}");auto*rbl=new QVBoxLayout(rbBox);rbl->setContentsMargins(24,20,24,20);rbl->setSpacing(12);auto*rbt=new QLabel("Recent Reservations");rbt->setStyleSheet("font-size:15px;font-weight:700;color:#1A1A2E;");rbl->addWidget(rbt);bookingTable=makeTable({"ID","Guest","Room","Check In","Check Out","Amount","Status"});bookingTable->setMaximumHeight(200);rbl->addWidget(bookingTable);lay->addWidget(rbBox);lay->addStretch();return pageWrap(lay);}
QWidget*MainWindow::buildRoomsPage(){auto*lay=new QVBoxLayout();lay->setContentsMargins(32,28,32,28);lay->setSpacing(20);auto*hdr=new QWidget();auto*hl=new QHBoxLayout(hdr);hl->setContentsMargins(0,0,0,0);hl->addWidget(new SectionHeader("Rooms","Manage all hotel rooms"));hl->addStretch();auto*search=styledInput("Search room number...");search->setFixedWidth(220);hl->addWidget(search);hl->addSpacing(8);auto*filter=styledCombo();filter->addItems({"All Rooms","Available","Occupied","Standard","Deluxe","Suite","Presidential"});hl->addWidget(filter);lay->addWidget(hdr);auto*box=new QFrame();box->setStyleSheet("QFrame{background:white;border-radius:16px;border:1px solid #F0EBE0;}");auto*bl=new QVBoxLayout(box);bl->setContentsMargins(20,18,20,18);roomTable=makeTable({"Room","Floor","Type","Price/Night","Amenities","Status","Action"});bl->addWidget(roomTable);lay->addWidget(box);lay->addStretch();connect(filter,&QComboBox::currentTextChanged,[this](const QString&f){for(int i=0;i<roomTable->rowCount();i++){bool show=true;if(f=="Available")show=roomTable->item(i,5)->text()=="Available";else if(f=="Occupied")show=roomTable->item(i,5)->text()=="Occupied";else if(f=="Standard"||f=="Deluxe"||f=="Suite"||f=="Presidential")show=roomTable->item(i,2)->text()==f;roomTable->setRowHidden(i,!show);}});connect(search,&QLineEdit::textChanged,[this](const QString&q){for(int i=0;i<roomTable->rowCount();i++)roomTable->setRowHidden(i,!q.isEmpty()&&!roomTable->item(i,0)->text().contains(q));});return pageWrap(lay);}
QWidget*MainWindow::buildGuestsPage(){auto*lay=new QVBoxLayout();lay->setContentsMargins(32,28,32,28);lay->setSpacing(20);auto*hdr=new QWidget();auto*hl=new QHBoxLayout(hdr);hl->setContentsMargins(0,0,0,0);hl->addWidget(new SectionHeader("Guests","All registered guests"));hl->addStretch();auto*search=styledInput("Search name, phone, email...");search->setFixedWidth(280);hl->addWidget(search);hl->addSpacing(8);auto*addBtn=goldBtn("+ Add Guest");connect(addBtn,&QPushButton::clicked,[this]{showAddGuestDialog();});hl->addWidget(addBtn);lay->addWidget(hdr);auto*box=new QFrame();box->setStyleSheet("QFrame{background:white;border-radius:16px;border:1px solid #F0EBE0;}");auto*bl=new QVBoxLayout(box);bl->setContentsMargins(20,18,20,18);guestTable=makeTable({"ID","Name","Phone","Email","ID Proof","Address"});bl->addWidget(guestTable);lay->addWidget(box);lay->addStretch();connect(search,&QLineEdit::textChanged,[this](const QString&q){for(int i=0;i<guestTable->rowCount();i++){bool show=q.isEmpty()||guestTable->item(i,1)->text().contains(q,Qt::CaseInsensitive)||guestTable->item(i,2)->text().contains(q,Qt::CaseInsensitive)||guestTable->item(i,3)->text().contains(q,Qt::CaseInsensitive);guestTable->setRowHidden(i,!show);}});return pageWrap(lay);}
QWidget*MainWindow::buildBookingPage(){auto*lay=new QVBoxLayout();lay->setContentsMargins(32,28,32,28);lay->setSpacing(20);auto*hdr=new QWidget();auto*hl=new QHBoxLayout(hdr);hl->setContentsMargins(0,0,0,0);hl->addWidget(new SectionHeader("Reservations","Manage all bookings"));hl->addStretch();auto*sf=styledCombo();sf->addItems({"All","Active","Checked Out","Cancelled"});hl->addWidget(sf);hl->addSpacing(8);auto*cb=outlineBtn("Check Out");connect(cb,&QPushButton::clicked,[this]{showCheckoutDialog();});hl->addWidget(cb);hl->addSpacing(8);auto*ab=goldBtn("+ New Reservation");connect(ab,&QPushButton::clicked,[this]{showAddBookingDialog();});hl->addWidget(ab);lay->addWidget(hdr);auto*box=new QFrame();box->setStyleSheet("QFrame{background:white;border-radius:16px;border:1px solid #F0EBE0;}");auto*bl=new QVBoxLayout(box);bl->setContentsMargins(20,18,20,18);auto*bt=makeTable({"ID","Guest","Room","Type","Check In","Check Out","Nights","Amount","Paid","Status"});bt->setObjectName("bookingTableFull");bl->addWidget(bt);lay->addWidget(box);lay->addStretch();connect(sf,&QComboBox::currentTextChanged,[bt](const QString&f){for(int i=0;i<bt->rowCount();i++)bt->setRowHidden(i,f!="All"&&bt->item(i,9)->text()!=f);});return pageWrap(lay);}
QWidget*MainWindow::buildBillingPage(){auto*lay=new QVBoxLayout();lay->setContentsMargins(32,28,32,28);lay->setSpacing(20);lay->addWidget(new SectionHeader("Billing","Payments & invoices"));auto*box=new QFrame();box->setStyleSheet("QFrame{background:white;border-radius:16px;border:1px solid #F0EBE0;}");auto*bl=new QVBoxLayout(box);bl->setContentsMargins(20,18,20,18);bl->setSpacing(12);auto*t=new QLabel("Active Reservations — Billing");t->setStyleSheet("font-size:15px;font-weight:700;color:#1A1A2E;");bl->addWidget(t);auto*billTable=makeTable({"Booking","Guest","Room","Room Charges","Restaurant","Laundry","Total","Paid","Balance","Action"});billTable->setObjectName("billTable");bl->addWidget(billTable);lay->addWidget(box);lay->addStretch();return pageWrap(lay);}
QWidget*MainWindow::buildRestaurantPage(){auto*lay=new QVBoxLayout();lay->setContentsMargins(32,28,32,28);lay->setSpacing(20);auto*hdr=new QWidget();auto*hl=new QHBoxLayout(hdr);hl->setContentsMargins(0,0,0,0);hl->addWidget(new SectionHeader("Restaurant","Room service & dining orders"));hl->addStretch();auto*ab=goldBtn("+ New Order");connect(ab,&QPushButton::clicked,[this]{showRestaurantOrderDialog();});hl->addWidget(ab);lay->addWidget(hdr);auto*box=new QFrame();box->setStyleSheet("QFrame{background:white;border-radius:16px;border:1px solid #F0EBE0;}");auto*bl=new QVBoxLayout(box);bl->setContentsMargins(20,18,20,18);auto*rt=makeTable({"Order ID","Room","Item","Qty","Amount","Time","Status","Paid","Action"});rt->setObjectName("restaurantTable");bl->addWidget(rt);lay->addWidget(box);lay->addStretch();return pageWrap(lay);}
QWidget*MainWindow::buildLaundryPage(){auto*lay=new QVBoxLayout();lay->setContentsMargins(32,28,32,28);lay->setSpacing(20);auto*hdr=new QWidget();auto*hl=new QHBoxLayout(hdr);hl->setContentsMargins(0,0,0,0);hl->addWidget(new SectionHeader("Laundry","Laundry service tracking"));hl->addStretch();auto*ab=goldBtn("+ New Laundry Order");connect(ab,&QPushButton::clicked,[this]{showLaundryOrderDialog();});hl->addWidget(ab);lay->addWidget(hdr);auto*box=new QFrame();box->setStyleSheet("QFrame{background:white;border-radius:16px;border:1px solid #F0EBE0;}");auto*bl=new QVBoxLayout(box);bl->setContentsMargins(20,18,20,18);auto*lt=makeTable({"Order ID","Room","Item","Qty","Amount","Order Date","Delivery","Delivered","Paid","Action"});lt->setObjectName("laundryTable");bl->addWidget(lt);lay->addWidget(box);lay->addStretch();return pageWrap(lay);}
QWidget*MainWindow::buildReportPage(){auto*lay=new QVBoxLayout();lay->setContentsMargins(32,28,32,28);lay->setSpacing(20);lay->addWidget(new SectionHeader("Reports","Hotel performance summary"));auto*box=new QFrame();box->setStyleSheet("QFrame{background:white;border-radius:16px;border:1px solid #F0EBE0;}");auto*bl=new QVBoxLayout(box);bl->setContentsMargins(24,20,24,20);bl->setSpacing(16);auto*title=new QLabel("Summary — "+QDate::currentDate().toString("MMMM yyyy"));title->setStyleSheet("font-size:16px;font-weight:700;color:#1A1A2E;");bl->addWidget(title);auto*sg=new QWidget();auto*sgl=new QGridLayout(sg);sgl->setSpacing(16);auto addStat=[&](int r,int c,const QString&lbl,const QString&val,const QString&color){auto*f=new QFrame();f->setStyleSheet(QString("QFrame{background:%1;border-radius:12px;border:none;}").arg(color));auto*fl=new QVBoxLayout(f);fl->setContentsMargins(20,16,20,16);auto*lv=new QLabel(val);lv->setStyleSheet("font-size:24px;font-weight:700;color:#1A1A2E;");auto*ll=new QLabel(lbl);ll->setStyleSheet("font-size:10px;color:#4A5568;letter-spacing:1.5px;font-weight:600;");fl->addWidget(lv);fl->addWidget(ll);sgl->addWidget(f,r,c);};int total=hotel.rooms.size(),avail=hotel.availableCount(),occ=hotel.occupiedCount();double oRate=total>0?(occ*100.0/total):0;double rRev=0,lRev=0;for(auto&o:hotel.restaurantOrders)if(o.isPaid)rRev+=o.amount;for(auto&o:hotel.laundryOrders)if(o.isPaid)lRev+=o.amount;addStat(0,0,"TOTAL ROOMS",QString::number(total),"#F0FFF4");addStat(0,1,"AVAILABLE",QString::number(avail),"#F0FFF4");addStat(0,2,"OCCUPIED",QString::number(occ),"#FFFBEB");addStat(0,3,"OCCUPANCY",QString::number(oRate,'f',1)+"%","#FFFBEB");addStat(1,0,"TOTAL GUESTS",QString::number(hotel.guests.size()),"#EBF8FF");addStat(1,1,"BOOKINGS",QString::number(hotel.bookings.size()),"#EBF8FF");addStat(1,2,"RESTAURANT",formatCurrency(rRev),"#FFF5F5");addStat(1,3,"LAUNDRY",formatCurrency(lRev),"#FFF5F5");addStat(2,0,"TOTAL REVENUE",formatCurrency(hotel.totalRevenue()),"#FAF5FF");addStat(2,1,"REST. ORDERS",QString::number(hotel.restaurantOrders.size()),"#F0F4FF");addStat(2,2,"LAUNDRY ORDERS",QString::number(hotel.laundryOrders.size()),"#F0F4FF");addStat(2,3,"DATA STATUS","Saved ✓","#F0FFF4");bl->addWidget(sg);lay->addWidget(box);lay->addStretch();return pageWrap(lay);}
void MainWindow::refreshDashboard(){if(statAvail)statAvail->setValue(QString::number(hotel.availableCount()));if(statOccupied)statOccupied->setValue(QString::number(hotel.occupiedCount()));if(statGuests)statGuests->setValue(QString::number(hotel.guests.size()));if(statRevenue)statRevenue->setValue(formatCurrency(hotel.totalRevenue()));if(!bookingTable)return;bookingTable->setRowCount(0);int count=0;for(int i=hotel.bookings.size()-1;i>=0&&count<8;i--,count++){auto&b=hotel.bookings[i];Guest*g=hotel.findGuest(b.guestId);int row=bookingTable->rowCount();bookingTable->insertRow(row);bookingTable->setItem(row,0,new QTableWidgetItem(QString::number(b.bookingId)));bookingTable->setItem(row,1,new QTableWidgetItem(g?g->name:"—"));bookingTable->setItem(row,2,new QTableWidgetItem(QString::number(b.roomNumber)));bookingTable->setItem(row,3,new QTableWidgetItem(b.checkIn.toString("dd/MM/yy")));bookingTable->setItem(row,4,new QTableWidgetItem(b.checkOut.toString("dd/MM/yy")));bookingTable->setItem(row,5,new QTableWidgetItem(formatCurrency(b.totalAmount)));auto*si=new QTableWidgetItem(b.statusStr());if(b.status==BookingStatus::ACTIVE)si->setForeground(QColor("#38A169"));else if(b.status==BookingStatus::CHECKED_OUT)si->setForeground(QColor("#3182CE"));else si->setForeground(QColor("#E53E3E"));bookingTable->setItem(row,6,si);}}
void MainWindow::refreshRoomTable(){if(!roomTable)return;roomTable->setRowCount(0);for(auto&r:hotel.rooms){int row=roomTable->rowCount();roomTable->insertRow(row);roomTable->setItem(row,0,new QTableWidgetItem(QString::number(r.number)));roomTable->setItem(row,1,new QTableWidgetItem(QString::number(r.floor)));roomTable->setItem(row,2,new QTableWidgetItem(r.typeName()));roomTable->setItem(row,3,new QTableWidgetItem(formatCurrency(r.pricePerNight())));roomTable->setItem(row,4,new QTableWidgetItem(r.amenities));auto*si=new QTableWidgetItem(r.isAvailable?"Available":"Occupied");si->setForeground(r.isAvailable?QColor("#38A169"):QColor("#D4AF37"));roomTable->setItem(row,5,si);auto*bw=new QWidget();auto*bl2=new QHBoxLayout(bw);bl2->setContentsMargins(6,4,6,4);auto*vb=outlineBtn("Details");vb->setFixedHeight(32);int rnum=r.number;connect(vb,&QPushButton::clicked,[this,rnum]{showRoomDetailDialog(rnum);});bl2->addWidget(vb);roomTable->setCellWidget(row,6,bw);}}
void MainWindow::refreshGuestTable(){if(!guestTable)return;guestTable->setRowCount(0);for(auto&g:hotel.guests){int row=guestTable->rowCount();guestTable->insertRow(row);guestTable->setItem(row,0,new QTableWidgetItem(QString::number(g.id)));guestTable->setItem(row,1,new QTableWidgetItem(g.name));guestTable->setItem(row,2,new QTableWidgetItem(g.phone));guestTable->setItem(row,3,new QTableWidgetItem(g.email));guestTable->setItem(row,4,new QTableWidgetItem(g.idProof));guestTable->setItem(row,5,new QTableWidgetItem(g.address));}}
void MainWindow::refreshBookingTable(){QTableWidget*bt=stack->findChild<QTableWidget*>("bookingTableFull");if(!bt)return;bt->setRowCount(0);for(auto&b:hotel.bookings){Guest*g=hotel.findGuest(b.guestId);Room*r=hotel.findRoom(b.roomNumber);int row=bt->rowCount();bt->insertRow(row);bt->setItem(row,0,new QTableWidgetItem(QString::number(b.bookingId)));bt->setItem(row,1,new QTableWidgetItem(g?g->name:"—"));bt->setItem(row,2,new QTableWidgetItem(QString::number(b.roomNumber)));bt->setItem(row,3,new QTableWidgetItem(r?r->typeName():"—"));bt->setItem(row,4,new QTableWidgetItem(b.checkIn.toString("dd/MM/yyyy")));bt->setItem(row,5,new QTableWidgetItem(b.checkOut.toString("dd/MM/yyyy")));bt->setItem(row,6,new QTableWidgetItem(QString::number(b.nights())+" nights"));bt->setItem(row,7,new QTableWidgetItem(formatCurrency(b.totalAmount)));bt->setItem(row,8,new QTableWidgetItem(formatCurrency(b.amountPaid)));auto*si=new QTableWidgetItem(b.statusStr());if(b.status==BookingStatus::ACTIVE)si->setForeground(QColor("#38A169"));else if(b.status==BookingStatus::CHECKED_OUT)si->setForeground(QColor("#3182CE"));else si->setForeground(QColor("#E53E3E"));bt->setItem(row,9,si);}}
void MainWindow::refreshBillingTable(){QTableWidget*bt=stack->findChild<QTableWidget*>("billTable");if(!bt)return;bt->setRowCount(0);for(auto&b:hotel.bookings){if(b.status!=BookingStatus::ACTIVE)continue;Guest*g=hotel.findGuest(b.guestId);double rA=hotel.pendingRestaurantBill(b.roomNumber);double lA=hotel.pendingLaundryBill(b.roomNumber);double tot=b.totalAmount+rA+lA;double bal=tot-b.amountPaid;int row=bt->rowCount();bt->insertRow(row);bt->setItem(row,0,new QTableWidgetItem(QString::number(b.bookingId)));bt->setItem(row,1,new QTableWidgetItem(g?g->name:"—"));bt->setItem(row,2,new QTableWidgetItem(QString::number(b.roomNumber)));bt->setItem(row,3,new QTableWidgetItem(formatCurrency(b.totalAmount)));bt->setItem(row,4,new QTableWidgetItem(formatCurrency(rA)));bt->setItem(row,5,new QTableWidgetItem(formatCurrency(lA)));bt->setItem(row,6,new QTableWidgetItem(formatCurrency(tot)));bt->setItem(row,7,new QTableWidgetItem(formatCurrency(b.amountPaid)));auto*balItem=new QTableWidgetItem(formatCurrency(bal));balItem->setForeground(bal>0?QColor("#E53E3E"):QColor("#38A169"));bt->setItem(row,8,balItem);auto*bw=new QWidget();auto*pl=new QHBoxLayout(bw);pl->setContentsMargins(6,4,6,4);auto*payBtn=goldBtn("Pay");payBtn->setFixedHeight(32);int bid=b.bookingId;connect(payBtn,&QPushButton::clicked,[this,bid]{showPaymentDialog(bid);});pl->addWidget(payBtn);bt->setCellWidget(row,9,bw);}}
void MainWindow::refreshRestaurantTable(){QTableWidget*rt=stack->findChild<QTableWidget*>("restaurantTable");if(!rt)return;rt->setRowCount(0);for(auto&o:hotel.restaurantOrders){int row=rt->rowCount();rt->insertRow(row);rt->setItem(row,0,new QTableWidgetItem(QString::number(o.orderId)));rt->setItem(row,1,new QTableWidgetItem(QString::number(o.roomNumber)));rt->setItem(row,2,new QTableWidgetItem(o.itemName));rt->setItem(row,3,new QTableWidgetItem(QString::number(o.quantity)));rt->setItem(row,4,new QTableWidgetItem(formatCurrency(o.amount)));rt->setItem(row,5,new QTableWidgetItem(o.orderTime.toString("dd/MM hh:mm")));auto*si=new QTableWidgetItem(o.status);if(o.status=="Delivered")si->setForeground(QColor("#38A169"));else if(o.status=="Preparing")si->setForeground(QColor("#D4AF37"));else si->setForeground(QColor("#E53E3E"));rt->setItem(row,6,si);auto*pi=new QTableWidgetItem(o.isPaid?"Paid":"Pending");pi->setForeground(o.isPaid?QColor("#38A169"):QColor("#E53E3E"));rt->setItem(row,7,pi);auto*bw=new QWidget();auto*bl2=new QHBoxLayout(bw);bl2->setContentsMargins(4,4,4,4);bl2->setSpacing(4);if(!o.isPaid){auto*pb=goldBtn("Pay");pb->setFixedHeight(30);int oid=o.orderId;connect(pb,&QPushButton::clicked,[this,oid]{for(auto&ord:hotel.restaurantOrders)if(ord.orderId==oid){ord.isPaid=true;hotel.saveRestaurantOrder(ord);break;}refreshRestaurantTable();refreshDashboard();});bl2->addWidget(pb);}if(o.status!="Delivered"){auto*db=successBtn("Deliver");db->setFixedHeight(30);int oid=o.orderId;connect(db,&QPushButton::clicked,[this,oid]{for(auto&ord:hotel.restaurantOrders)if(ord.orderId==oid){ord.status="Delivered";hotel.saveRestaurantOrder(ord);break;}refreshRestaurantTable();});bl2->addWidget(db);}rt->setCellWidget(row,8,bw);}}
void MainWindow::refreshLaundryTable(){QTableWidget*lt=stack->findChild<QTableWidget*>("laundryTable");if(!lt)return;lt->setRowCount(0);for(auto&o:hotel.laundryOrders){int row=lt->rowCount();lt->insertRow(row);lt->setItem(row,0,new QTableWidgetItem(QString::number(o.orderId)));lt->setItem(row,1,new QTableWidgetItem(QString::number(o.roomNumber)));lt->setItem(row,2,new QTableWidgetItem(o.itemName));lt->setItem(row,3,new QTableWidgetItem(QString::number(o.quantity)));lt->setItem(row,4,new QTableWidgetItem(formatCurrency(o.amount)));lt->setItem(row,5,new QTableWidgetItem(o.orderDate.toString("dd/MM/yyyy")));lt->setItem(row,6,new QTableWidgetItem(o.deliveryDate.toString("dd/MM/yyyy")));auto*di=new QTableWidgetItem(o.isDelivered?"Yes":"No");di->setForeground(o.isDelivered?QColor("#38A169"):QColor("#D4AF37"));lt->setItem(row,7,di);auto*pi=new QTableWidgetItem(o.isPaid?"Paid":"Pending");pi->setForeground(o.isPaid?QColor("#38A169"):QColor("#E53E3E"));lt->setItem(row,8,pi);auto*bw=new QWidget();auto*bl2=new QHBoxLayout(bw);bl2->setContentsMargins(4,4,4,4);bl2->setSpacing(4);if(!o.isDelivered){auto*db=successBtn("Deliver");db->setFixedHeight(30);int oid=o.orderId;connect(db,&QPushButton::clicked,[this,oid]{for(auto&ord:hotel.laundryOrders)if(ord.orderId==oid){ord.isDelivered=true;hotel.saveLaundryOrder(ord);break;}refreshLaundryTable();});bl2->addWidget(db);}if(!o.isPaid){auto*pb=goldBtn("Pay");pb->setFixedHeight(30);int oid=o.orderId;connect(pb,&QPushButton::clicked,[this,oid]{for(auto&ord:hotel.laundryOrders)if(ord.orderId==oid){ord.isPaid=true;hotel.saveLaundryOrder(ord);break;}refreshLaundryTable();refreshDashboard();});bl2->addWidget(pb);}lt->setCellWidget(row,9,bw);}}
void MainWindow::showAddGuestDialog(){auto*dlg=new QDialog(this);dlg->setWindowTitle("Register New Guest");dlg->setFixedWidth(480);dlg->setStyleSheet("QDialog{background:#FAFAF7;}QLabel{color:#2D3748;}");auto*lay=new QVBoxLayout(dlg);lay->setContentsMargins(28,28,28,28);lay->setSpacing(20);auto*hdr=new QWidget();hdr->setStyleSheet("background:#1A1A2E;border-radius:12px;");auto*hl=new QVBoxLayout(hdr);hl->setContentsMargins(20,16,20,16);auto*ht=new QLabel("Register New Guest");ht->setStyleSheet("color:#D4AF37;font-size:18px;font-weight:700;");auto*hs=new QLabel("Fill in guest details below");hs->setStyleSheet("color:rgba(255,255,255,0.5);font-size:12px;");hl->addWidget(ht);hl->addWidget(hs);lay->addWidget(hdr);auto*form=new QFormLayout();form->setSpacing(12);form->setLabelAlignment(Qt::AlignRight);auto*nameE=styledInput("Enter full name");auto*phoneE=styledInput("Enter phone number");auto*emailE=styledInput("Enter email address");auto*idE=styledInput("Aadhaar / Passport / DL number");auto*addrE=styledInput("City, State");auto addRow=[&](const QString&l,QLineEdit*w){auto*lbl=new QLabel(l);lbl->setStyleSheet("color:#4A5568;font-size:12px;font-weight:600;");form->addRow(lbl,w);};addRow("Full Name *",nameE);addRow("Phone *",phoneE);addRow("Email",emailE);addRow("ID Proof *",idE);addRow("Address",addrE);lay->addLayout(form);auto*btns=new QHBoxLayout();btns->addStretch();auto*cancel=outlineBtn("Cancel");auto*save=goldBtn("Register Guest");connect(cancel,&QPushButton::clicked,dlg,&QDialog::reject);connect(save,&QPushButton::clicked,[&]{if(nameE->text().trimmed().isEmpty()||phoneE->text().trimmed().isEmpty()||idE->text().trimmed().isEmpty()){QMessageBox::warning(dlg,"Required Fields","Name, Phone and ID Proof are required.");return;}Guest g(hotel.nextGuestId++,nameE->text().trimmed(),phoneE->text().trimmed(),emailE->text().trimmed(),idE->text().trimmed(),addrE->text().trimmed());hotel.guests.push_back(g);hotel.saveGuest(g);refreshGuestTable();refreshDashboard();QMessageBox::information(dlg,"Success",QString("Guest '%1' registered successfully!\nGuest ID: %2").arg(g.name).arg(g.id));dlg->accept();});btns->addWidget(cancel);btns->addSpacing(8);btns->addWidget(save);lay->addLayout(btns);dlg->exec();}
void MainWindow::showAddBookingDialog(){if(hotel.guests.empty()){QMessageBox::warning(this,"No Guests","Please register a guest first.");return;}auto*dlg=new QDialog(this);dlg->setWindowTitle("New Reservation");dlg->setFixedWidth(520);dlg->setStyleSheet("QDialog{background:#FAFAF7;}QLabel{color:#2D3748;}");auto*lay=new QVBoxLayout(dlg);lay->setContentsMargins(28,28,28,28);lay->setSpacing(20);auto*hdr=new QWidget();hdr->setStyleSheet("background:#1A1A2E;border-radius:12px;");auto*hl=new QVBoxLayout(hdr);hl->setContentsMargins(20,16,20,16);auto*ht=new QLabel("New Reservation");ht->setStyleSheet("color:#D4AF37;font-size:18px;font-weight:700;");auto*hs=new QLabel("Select guest, room and dates");hs->setStyleSheet("color:rgba(255,255,255,0.5);font-size:12px;");hl->addWidget(ht);hl->addWidget(hs);lay->addWidget(hdr);auto*form=new QFormLayout();form->setSpacing(12);form->setLabelAlignment(Qt::AlignRight);auto*guestCombo=styledCombo();for(auto&g:hotel.guests)guestCombo->addItem(QString("#%1 — %2 (%3)").arg(g.id).arg(g.name).arg(g.phone),g.id);auto*roomCombo=styledCombo();for(auto&r:hotel.rooms)if(r.isAvailable)roomCombo->addItem(QString("Room %1 | %2 | %3/night").arg(r.number).arg(r.typeName()).arg(formatCurrency(r.pricePerNight())),r.number);if(roomCombo->count()==0){QMessageBox::information(this,"No Rooms","No rooms available at the moment.");return;}auto*checkInE=styledDate();auto*checkOutE=styledDate();checkOutE->setDate(QDate::currentDate().addDays(1));auto*amtBox=new QFrame();amtBox->setStyleSheet("QFrame{background:#FFFBEB;border-radius:8px;border:1.5px solid #D4AF37;}");auto*abl=new QHBoxLayout(amtBox);abl->setContentsMargins(16,12,16,12);auto*amtLabel=new QLabel("Rs. 0");amtLabel->setStyleSheet("font-size:20px;font-weight:700;color:#D4AF37;");auto*amtSub=new QLabel("Total Amount");amtSub->setStyleSheet("font-size:11px;color:#92400E;");auto*abv=new QVBoxLayout();abv->addWidget(amtLabel);abv->addWidget(amtSub);abl->addLayout(abv);abl->addStretch();auto calcAmount=[&](){int rnum=roomCombo->currentData().toInt();Room*r=hotel.findRoom(rnum);int nights=checkInE->date().daysTo(checkOutE->date());if(r&&nights>0){amtLabel->setText(formatCurrency(r->pricePerNight()*nights));amtSub->setText(QString("%1 nights x %2").arg(nights).arg(formatCurrency(r->pricePerNight())));}else{amtLabel->setText("Rs. 0");amtSub->setText("Select room and dates");}};connect(roomCombo,&QComboBox::currentIndexChanged,[&](int){calcAmount();});connect(checkInE,&QDateEdit::dateChanged,[&](QDate){calcAmount();});connect(checkOutE,&QDateEdit::dateChanged,[&](QDate){calcAmount();});auto addRow=[&](const QString&l,QWidget*w){auto*lbl=new QLabel(l);lbl->setStyleSheet("color:#4A5568;font-size:12px;font-weight:600;");form->addRow(lbl,w);};addRow("Guest *",guestCombo);addRow("Room *",roomCombo);addRow("Check In *",checkInE);addRow("Check Out *",checkOutE);addRow("Total",amtBox);auto*notesE=new QTextEdit();notesE->setPlaceholderText("Special requests, preferences...");notesE->setMaximumHeight(70);notesE->setStyleSheet("QTextEdit{background:#FAFAFA;border:1.5px solid #E8E0D0;border-radius:8px;padding:8px;font-size:13px;color:#2D3748;}QTextEdit:focus{border:1.5px solid #D4AF37;}");addRow("Notes",notesE);lay->addLayout(form);calcAmount();auto*btns=new QHBoxLayout();btns->addStretch();auto*cancel=outlineBtn("Cancel");auto*save=goldBtn("Confirm Reservation");connect(cancel,&QPushButton::clicked,dlg,&QDialog::reject);connect(save,&QPushButton::clicked,[&]{if(checkInE->date()>=checkOutE->date()){QMessageBox::warning(dlg,"Invalid Dates","Check-out must be after check-in.");return;}int gid=guestCombo->currentData().toInt(),rnum=roomCombo->currentData().toInt();Room*r=hotel.findRoom(rnum);if(!r||!r->isAvailable){QMessageBox::warning(dlg,"Unavailable","Room is not available.");return;}int nights=checkInE->date().daysTo(checkOutE->date());Booking b;b.bookingId=hotel.nextBookingId++;b.guestId=gid;b.roomNumber=rnum;b.checkIn=checkInE->date();b.checkOut=checkOutE->date();b.status=BookingStatus::ACTIVE;b.totalAmount=r->pricePerNight()*nights;b.amountPaid=0;b.notes=notesE->toPlainText();hotel.bookings.push_back(b);hotel.saveBooking(b);r->isAvailable=false;hotel.saveRoomStatus(rnum,false);refreshDashboard();refreshRoomTable();refreshBookingTable();Guest*g=hotel.findGuest(gid);QMessageBox::information(dlg,"Reservation Confirmed!",QString("Booking #%1 confirmed!\n\nGuest: %2\nRoom: %3 (%4)\nDates: %5 to %6\nNights: %7\nTotal: %8").arg(b.bookingId).arg(g?g->name:"—").arg(rnum).arg(r->typeName()).arg(b.checkIn.toString("dd/MM/yyyy")).arg(b.checkOut.toString("dd/MM/yyyy")).arg(nights).arg(formatCurrency(b.totalAmount)));dlg->accept();});btns->addWidget(cancel);btns->addSpacing(8);btns->addWidget(save);lay->addLayout(btns);dlg->exec();}
void MainWindow::showCheckoutDialog(){auto*dlg=new QDialog(this);dlg->setWindowTitle("Guest Check Out");dlg->setFixedWidth(440);dlg->setStyleSheet("QDialog{background:#FAFAF7;}QLabel{color:#2D3748;}");auto*lay=new QVBoxLayout(dlg);lay->setContentsMargins(28,28,28,28);lay->setSpacing(16);auto*hdr=new QWidget();hdr->setStyleSheet("background:#1A1A2E;border-radius:12px;");auto*hl=new QVBoxLayout(hdr);hl->setContentsMargins(20,16,20,16);auto*ht=new QLabel("Check Out Guest");ht->setStyleSheet("color:#D4AF37;font-size:18px;font-weight:700;");auto*hs=new QLabel("Select active booking to check out");hs->setStyleSheet("color:rgba(255,255,255,0.5);font-size:12px;");hl->addWidget(ht);hl->addWidget(hs);lay->addWidget(hdr);auto*combo=styledCombo();combo->setMinimumWidth(380);for(auto&b:hotel.bookings){if(b.status==BookingStatus::ACTIVE){Guest*g=hotel.findGuest(b.guestId);combo->addItem(QString("Booking #%1 — %2 | Room %3").arg(b.bookingId).arg(g?g->name:"—").arg(b.roomNumber),b.bookingId);}}if(combo->count()==0){QMessageBox::information(this,"No Active Bookings","There are no active bookings to check out.");return;}lay->addWidget(combo);auto*btns=new QHBoxLayout();btns->addStretch();auto*cancel=outlineBtn("Cancel");auto*btn=dangerBtn("Confirm Check Out");connect(cancel,&QPushButton::clicked,dlg,&QDialog::reject);connect(btn,&QPushButton::clicked,[&]{int bid=combo->currentData().toInt();Booking*b=hotel.findBooking(bid);if(!b)return;double totalBal=b->balance()+hotel.pendingRestaurantBill(b->roomNumber)+hotel.pendingLaundryBill(b->roomNumber);if(totalBal>0){auto res=QMessageBox::question(dlg,"Pending Balance",QString("This guest has a pending balance of %1.\n\nCheck out anyway?").arg(formatCurrency(totalBal)),QMessageBox::Yes|QMessageBox::No);if(res!=QMessageBox::Yes)return;}b->status=BookingStatus::CHECKED_OUT;hotel.saveBooking(*b);Room*r=hotel.findRoom(b->roomNumber);if(r){r->isAvailable=true;hotel.saveRoomStatus(r->number,true);}refreshDashboard();refreshRoomTable();refreshBookingTable();refreshBillingTable();Guest*g=hotel.findGuest(b->guestId);QMessageBox::information(dlg,"Checked Out Successfully",QString("%1 has been checked out from Room %2.\nThank you for staying at Grand Azure!").arg(g?g->name:"Guest").arg(b->roomNumber));dlg->accept();});btns->addWidget(cancel);btns->addSpacing(8);btns->addWidget(btn);lay->addLayout(btns);dlg->exec();}
void MainWindow::showPaymentDialog(int bookingId){Booking*b=hotel.findBooking(bookingId);if(!b)return;Guest*g=hotel.findGuest(b->guestId);double rBal=hotel.pendingRestaurantBill(b->roomNumber);double lBal=hotel.pendingLaundryBill(b->roomNumber);double tot=b->balance()+rBal+lBal;auto*dlg=new QDialog(this);dlg->setWindowTitle("Record Payment");dlg->setFixedWidth(420);dlg->setStyleSheet("QDialog{background:#FAFAF7;}QLabel{color:#2D3748;}");auto*lay=new QVBoxLayout(dlg);lay->setContentsMargins(28,28,28,28);lay->setSpacing(16);auto*hdr=new QWidget();hdr->setStyleSheet("background:#1A1A2E;border-radius:12px;");auto*hl=new QVBoxLayout(hdr);hl->setContentsMargins(20,16,20,16);auto*ht=new QLabel("Record Payment");ht->setStyleSheet("color:#D4AF37;font-size:18px;font-weight:700;");hl->addWidget(ht);lay->addWidget(hdr);auto*info=new QFrame();info->setStyleSheet("QFrame{background:#F0FFF4;border-radius:10px;border:1px solid #9AE6B4;}");auto*il=new QVBoxLayout(info);il->setContentsMargins(16,14,16,14);il->setSpacing(6);auto*il1=new QLabel(QString("Booking #%1 — %2 | Room %3").arg(b->bookingId).arg(g?g->name:"").arg(b->roomNumber));il1->setStyleSheet("font-weight:700;color:#1A1A2E;font-size:14px;");auto*il2=new QLabel(QString("Room: %1  |  Restaurant: %2  |  Laundry: %3").arg(formatCurrency(b->balance())).arg(formatCurrency(rBal)).arg(formatCurrency(lBal)));il2->setStyleSheet("color:#276749;font-size:12px;");auto*il3=new QLabel(QString("Total Due: %1").arg(formatCurrency(tot)));il3->setStyleSheet("color:#276749;font-size:15px;font-weight:700;");il->addWidget(il1);il->addWidget(il2);il->addWidget(il3);lay->addWidget(info);auto*amtE=styledInput("Enter payment amount");amtE->setText(QString::number((long long)tot));lay->addWidget(new QLabel("Payment Amount (Rs.):"));lay->addWidget(amtE);auto*btns=new QHBoxLayout();btns->addStretch();auto*cancel=outlineBtn("Cancel");auto*pay=goldBtn("Confirm Payment");connect(cancel,&QPushButton::clicked,dlg,&QDialog::reject);connect(pay,&QPushButton::clicked,[&]{double amt=amtE->text().toDouble();if(amt<=0){QMessageBox::warning(dlg,"Invalid","Please enter a valid amount.");return;}b->amountPaid+=amt;hotel.saveBooking(*b);refreshBillingTable();refreshDashboard();QMessageBox::information(dlg,"Payment Recorded",QString("Payment of %1 recorded successfully!").arg(formatCurrency(amt)));dlg->accept();});btns->addWidget(cancel);btns->addSpacing(8);btns->addWidget(pay);lay->addLayout(btns);dlg->exec();}
